import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def is_within_time_window(node_index, arrival_time):
        start, end = time_windows[node_index]
        return start <= arrival_time <= end

    def waiting_time(node_index, arrival_time):
        start, end = time_windows[node_index]
        if arrival_time < start:
            return start - arrival_time
        else:
            return 0

    min_cost = float('inf')
    best_node = None

    # Go through all unvisited customers and calculate the practical cost
    for index, customer in enumerate(unvisited_customers):
        travel_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_to_customer
        if is_within_time_window(index, arrival_time):
            # Calculate cost considering waiting time if early
            waiting = waiting_time(index, arrival_time)
            adjusted_arrival_time = arrival_time + waiting
            # Simplicity cost: just travel time at first
            total_cost = travel_to_customer + waiting
        else:
            # Assigned a high penalty if outside of the time window
            total_cost = float('inf')

        # Checking if this cost is the minimum found so far
        if total_cost < min_cost:
            min_cost = total_cost
            best_node = index

    return best_node
